213	    const knownTimestamp = "2026-04-09T12:30:00Z";
214	    mockUseSession.mockReturnValue(configuredSession);
215	    mockUseAccountRisk.mockReturnValue({
216	      ...emptyQueryResult,
217	      data: makeRiskData({ updatedAt: knownTimestamp }),
